import React from 'react';
import { Card, Stack, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = '°C',
    forecast,
  } = props;

  return (
    <Card shadow="md" radius="xl" padding={24}>
      <Stack direction="vertical" gap={24}>
        {/* Header Section */}
        <Stack direction="vertical" gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface)">
            {city}
          </Heading>
          <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
            {condition}
          </Text>
        </Stack>

        {/* Temperature Display */}
        <Text 
          size="4xl" 
          weight="bold" 
          color="var(--ggui-color-primary-600)" 
          align="center"
        >
          {temperature}{unit}
        </Text>

        {/* Stats Section */}
        <Stack direction="horizontal" justify="between">
          <Stack direction="vertical" gap={4} align="center">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
              Humidity
            </Text>
            <Text weight="medium">{humidity}%</Text>
          </Stack>
          <Stack direction="vertical" gap={4} align="center">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
              Wind
            </Text>
            <Text weight="medium">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant)" />

        {/* Forecast Section */}
        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((f, i) => (
            <Stack key={i} align="center" gap={8}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                {f.day ?? 'N/A'}
              </Text>
              <Text size="2xl">{f.icon ?? '☁️'}</Text>
              <Text variant="bodySmall" weight="medium">
                {f.high}°/{f.low}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
